"use strict";(self.webpackChunkpersonal_site=self.webpackChunkpersonal_site||[]).push([[964],{964:function(n,a,e){e.r(a);var t=e(8683),o=(e(2791),e(1523)),r=e(2068),i=e.n(r),s=e(6842),l=e(184),h="\n# Intro\n\nBla bla\n\n# Currently\n\nBli bli\n\n# Some history\n\n- Ble\n\n- ble\n\n# I like\n\n- The blue sea\n- Chocolate\n- Yoga\n- Summer\n- [Books](https://app.thestorygraph.com/profile/ladychristina)\n- Podcasts ([Lex Fridman](https://lexfridman.com/podcast/), [Huberman Lab](https://hubermanlab.com/), [The Tim Ferriss Show](https://tim.blog/podcast/), and others)\n\n\n\x3c!-- # Travel / Geography\n\n- I am from originally from Buffalo, New York. I have since lived in Palo Alto, Mountain View, San Francisco, Seattle, and New York.\n- I've been to ~ 50 countries, some of which I have forgotten, and many of which I would like to revisit.\n- In 2016, I visited: Canada, Ethiopia, Austria, Germany, Belgium, Ireland, Northern Ireland, Italy, Romania, Sweden, Norway, Svalbard, Panama, Costa Rica, Uganda, Japan, and the UAE, mostly in that order.\n- In 2017, I visited: Canada, Japan, Denmark, Germany, Sweden, Estonia, Russia, the Netherlands, Belgium, the U.K., Spain, Iceland, France, Switzerland, Ethiopia, and Luxembourg.\n- In 2018, I visited: Canada, France, Italy, Israel, and the U.K.\n- In 2019, I visited: Canada, England, France, and Switzerland.\n- In 2020, I barely traveled 20 blocks. I stayed in New York and remodeled an apartment.\n- In 2021, I hope to start traveling again.\n- I am an Oregon Trail II enthusiast.\n\n# Fun facts\n\n- I have a list of thousands of ideas, like creating matching bow ties for cats and humans.\n- I almost always have a sketchbook with me and a [01 Sakura Pigma Micron Pen](https://www.sakuraofamerica.com/product/pigma-micron/).\n- I can't locate every country on a map.\n- I operate a [small angel fund](http://skepticalinvestments.biz/) with terrible returns.\n- I break about 30 traffic laws on a [cruiser](https://landyachtz.com/boards/cruiser/), [onewheel](https://onewheel.com/products/xr), [bicycle](https://www.citibikenyc.com/), or [electric skateboard](https://boostedusa.com/collections/electric-skateboards/products/boosted-mini-x) every single day.\n- I added this page because so many people complained that my site was just my resume.\n\n# I dream of\n\n- always finding inspiration.\n- enabling a brighter future.\n- doing better.\n- you not checking the commit history for earlier drafts of this file.\n\n# Websites from people I admire\n\n- [Alex Peysakhovich](http://alexpeys.github.io/)\n- [Chris Lengerich](http://www.chrislengerich.com/)\n- [Chris Saad](https://www.chrissaad.com/)\n- [Duncan Tomlin](http://duncantomlin.com/)\n- [Hawley Moore](http://hawleymoore.com/)\n- [Holman Gao](https://golmansax.com/)\n- [Ian Webster](http://ianww.com/)\n- [Johanna Flato](https://www.johannaflato.com/)\n- [Judy Mou](http://www.judymou.com/)\n- [Kristina Monakhova](https://kristinamonakhova.com/)\n- [Noah Trueblood](http://notrueblood.com/)\n- [Ruoxi Wang](http://ruoxiw.com/)\n- [Tom Sachs](https://www.tomsachs.org/)\n- [Will Holley](https://willholley.com)\n\nIf we are friends and you feel like you belong on this list, you're probably right. I'm sorry I forgot about you. Pester me and I'll add you. --\x3e\n",c=h.split(/\s+/).map((function(n){return n.replace(/\W/g,"")})).filter((function(n){return n.length})).length,d=function(n){var a=Object.assign({},n);return(0,l.jsx)(o.rU,(0,t.Z)({},a))};a.default=function(){return(0,l.jsx)(s.Z,{title:"About",description:"Learn about Christina Ovezik",children:(0,l.jsxs)("article",{className:"post markdown",id:"about",children:[(0,l.jsx)("header",{children:(0,l.jsxs)("div",{className:"title",children:[(0,l.jsx)("h2",{"data-testid":"heading",children:(0,l.jsx)(o.rU,{to:"/about",children:"About Me"})}),(0,l.jsxs)("p",{children:["(in about ",c," words)"]})]})}),(0,l.jsx)(i(),{source:h,renderers:{Link:d},escapeHtml:!1})]})})}}}]);
